(10066, 'lt', 'support', 'support_cont1', '<fieldset>\r\n<legend> SEO Panel Support System </legend>\r\n<ul class=\"infobox\">\r\n    <li>\r\n        <h1> 1000 katalogas paketas </h1>\r\n        <p>\r\n            Mes teikiame <b> 1000 nemokamų aktyvus ir patikrinta </b> Internet Directory paketas, pridėti į\r\njūsų SEO skydelis <b> katalogas pateikimo įrankis </b>.\r\n            Tai padės jums <b> padidinti Atgalinės nuorodos </b> savo interneto svetainėse.\r\n            Tiesą sakant, 1000 Rodyklės sąrašas <b> pristatė </b> surinkti šiek tiek pinigų <b> ateitis\r\nplėtra </b> SEO skydelyje.\r\n            Gauti 1000 katalogas sąrašas prašome <a href = \"<?=SP_DONATE_LINK?>\" Target = \"_blank\"> dovanoti </a>\r\n$ 10 ar daugiau, siekiant pagerinti SEO skydelio funkcijas.\r\n            Jei turite klausimų apie 1000 katalogo paketą, prašome <a href = \"<?=SP_CONTACT_LINK?>\"\r\ntarget = \"_blank\"> Susisiekite su mumis </a> arba atidaryti bilietą <a href = \"<?=SP_SUPPORT_LINK?>\"\r\ntarget = \"_blank\"> palaikymo sistema </a>.\r\n        </P>\r\n        <p>\r\n            <A href = \"<?=SP_DONATE_LINK?>\" Target = \"_blank\"> Aplankykite šią nuorodą, norėdami paaukoti SEO skydelyje </a>\r\n        </P>\r\n        <br>\r\n    </Li>\r\n     \r\n    <li>\r\n        <h1> Vietinė paieška Varikliai paketas </h1>\r\n        <p>\r\n            Pridėti <b> vietos paieškos domenų </b>, Google, Yahoo, MSN (<b> pvz.: www.google.de, www.google.fr\r\ntt </b>) SEO skydelio <b> raktinio žodžio poziciją tikrintuvas </b>, sekti savo svetainės Perfomance vietoje.\r\n            Gauti vietos paieškos variklius paketą (pagal jūsų reikalavimą) <a\r\nhref = \"<?=SP_DONATE_LINK?>\" target = \"_blank\"> dovanoti </a>, $ 10 ar daugiau, siekiant pagerinti SEO funkcijos\r\nskydelis.\r\n            Prieš siųsdami donorystei, prašome <a href = \"<?=SP_CONTACT_LINK?>\" Target = \"_blank\"> Susisiekite su mumis </a>, kad\r\nPateikite mums reikalingą paieškos domeno sąrašą.\r\n            <br>\r\n            Taip pat pridėti <b> paieškos sistemų (pvz.: baidu.com) </b> savo SEO skydelio raktinio žodžio poziciją tikrintuvas,\r\nprašom <a href = \"<?=SP_CONTACT_LINK?>\" target = \"_blank\"> Susisiekite su mumis </a> arba atidaryti bilietą <a\r\nhref = \"<?=SP_SUPPORT_LINK?>\" target = \"_blank\"> palaikymo sistema </a>.\r\n        </P>\r\n        <p class=\"visit\">\r\n            <A href = \"<?=SP_CONTACT_LINK?>\" Target = \"_blank\"> Aplankykite šią nuorodą, susisiekite su mumis </a>\r\n        </P>\r\n        <br>\r\n    </Li>\r\n     \r\n    <li>\r\n        <h1> SEO Panel Įskiepiai </h1>\r\n        <p>\r\n            Pridėkite <b> SEO įskiepių </b>, kad jūsų SEO skydelyje <b> išplėsti funkcijas </b> pagal jūsų\r\nreikalavimas.\r\n            <A href = \"<?=SP_PLUGINSITE?>\" Target = \"_blank\"> SEO įskiepių skydelio </a> yra tiek SEO lange\r\nir trečiųjų šalių svetainių.\r\n            Taip pat galite lengvai <b> sukurti </b> SEO įskiepių jūsų SEO skydelyje.\r\n            Galite <a href = \"<?=SP_PLUGINSITE?>\" Target = \"_blank\"> išsiųskite </a> jūsų SEO įskiepiai SEO skydelyje ir\r\nmes <b> Publikuoti </b> mūsų svetainėje po mūsų <b> peržiūros </b> proceso.\r\n        </P>\r\n        <p>\r\n            <A href = \"<?=SP_PLUGINSITE?>\" Target = \"_blank\"> Aplankykite šią nuorodą, norėdami gauti SEO skydelis įskiepių </a>\r\n        </P>\r\n        <br>\r\n    </Li>\r\n    <li>\r\n        <h1> Kontaktai </h1>\r\n        <p>\r\n            Susisiekite su mumis dėl kiltų klausimų apie <b> SEO Panel įrankių, įskiepių ir funkcijos ir tt </b> naudodami žemiau\r\nnuorodą.\r\n        </P>\r\n        <p>\r\n            <A href = \"<?=SP_CONTACT_LINK?>\" Target = \"_blank\"> Aplankykite šią nuorodą, susisiekite su mumis </a>\r\n        </P>\r\n        <br>\r\n    </Li>\r\n    <li>\r\n        <h1> Palaikymo Bilietai </h1>\r\n        <p>\r\n            Gauti <b> techninę pagalbą </b> SEO skydelio komanda sukonfigūruoti į <b> seo pulto priemones, įskiepių ir\r\nfunkcijų </b>. Pvz.: Norėdami sukurti cron raktinio žodžio poziciją tikrintuvas.\r\n        </P>\r\n        <p>\r\n            <A href = \"<?=SP_SUPPORT_LINK>\" target = \"_blank\"> Apsilankykite šią nuorodą, norėdami sukurti paramos bilietą </a>\r\n        </P>\r\n        <br>\r\n    </Li>\r\n    <li>\r\n        <h1> pranešti apie klaidas </h1>\r\n        <p>\r\n            Pranešti <b> klaidas </b> apie <b> seo skydelio įrankiai, įskiepių ir funkcijos ir tt </b> naudodami žemiau nuorodą.\r\n            prašome padėti mums pagerinti funkcijų, vėlesnėse redakcijose.\r\n        </P>\r\n        <p>\r\n            <A href = \"<?=SP_SUPPORT_LINK?>\" Target = \"_blank\"> Aplankykite šią nuorodą, norėdami pranešti apie klaidas </a>\r\n        </P>\r\n        <br>\r\n    </Li>\r\n</Ul>\r\n</Fieldset>', '2012-11-07 18:09:31'),
