(10067, 'lt', 'support', 'support_cont2', '<fieldset>\r\n<legend> SEO Panel Online ištekliai </legend>\r\n<ul class=\"infobox\">\r\n         \r\n    <li>\r\n        <h1> SEO Panel Pagalba vadovas </h1>\r\n        <p>\r\n            <A href = \"<?=SP_HELP_LINK?>\" Target = \"_blank\"> SEO skydelis dokumentacijos </a> galite peržiūrėti\r\n<b> Pagalba gidas </b>, yra <b> dokumentus </b> SEO skydelio įrankiai, įskiepių ir su jais susijusi\r\nfunkcijos.\r\n            IT yra geriausia vieta internete <b> gauti pagalbos </b> apie SEO skydelyje. Tikimės, kad Jūs\r\n<b> prisidėti </b>, SEO skydelio pagalbos vadovą, jei radote klaidų ar daiktus trūkstamas.\r\n        </p>\r\n        <p>\r\n            <a href = \"<?=SP_HELP_LINK>\" target = \"_blank\"> Visit SEO skydelis Pagalba gidas </a>\r\n        </p>\r\n        <br>\r\n    </li>\r\n    <li>\r\n        <h1> SEO Panel Forumas </h1>\r\n        <p>\r\n            Vieta diskutuoti apie pirmąjį pasaulyje atviro kodo <b> SEO valdymo skydelio </b>.\r\n            Tai yra geriausia vieta rasti <b> atsakymus </b> <b> jūsų klausimus </b> apie SEO skydelyje.\r\n            <br> Taip pat galite <b> dalis </b> Jūsų <b> patirtis </b>, naudojant SEO, kaip optimizuoti savo skydelį\r\ninterneto svetainėse.\r\n        </p>\r\n        <p>\r\n            <a href = \"<?=SP_FORUM_LINK?>\" target = \"_blank\"> Visit SEO skydelis forumas </a>\r\n        </p>\r\n        <br>\r\n    </li>\r\n</ul>\r\n</fieldset>', '2012-11-07 18:09:31'),
(10068, 'lt', 'support', 'support_cont3', '<fieldset>\r\n<legend> Paaukoti SEO skydo </legend>\r\n<ul class=\"infobox\">\r\n    <li>\r\n        <h1> Paaukoti SEO Panel - Pirmasis atviras šaltinis SEO valdymo pulto pasaulyje </h1>\r\n        <p>\r\n            <b> Paaukok </b> SEO kolegiją remti pirmąją atviro kodo SEO valdymo pultą pasaulyje.\r\n            Mes planuojame <b> pridėti ir pagerinti </b> SEO skydelio savybes ateityje.\r\n            , <br> <b> paramą </b> tik mes galime pasiekti mūsų <b> tikslus </b>.\r\n            Jei manote, kad SEO skydelis yra <b> verta </b> jums, prašome paaukoti tam tikrą sumą SEO skydelio komanda.\r\n            <br> <b> Publikuoti </b> savo vardą ir svetainės informacija <a href = \"<?=SP_DONATE_LINK?>\"\r\ntarget = \"_blank\"> donorystė puslapis </a>, kai mes gauname donorystę.\r\n        </p>\r\n        <p>\r\n            <a href = \"<?=SP_DONATE_LINK?>\" target = \"_blank\"> Aplankykite šią nuorodą, norėdami paaukoti SEO skydelyje </a>\r\n        </p>\r\n        <br>\r\n    </li>\r\n</ul>\r\n</fieldset>', '2012-11-07 18:09:31'),
